arguments.content:
$agents = Get-ChildItem .openclaw/agents/*.json
$docsPath = "C:\Users\west2\AppData\Roaming\npm\node_modules\openclaw\docs"
foreach ($agent in $agents) {
    $json = Get-Content $agent.FullName | ConvertFrom-Json
    $system = $json.system
    if ($system -notmatch "DOCUMENTATION") {
        $json.system = $system + "`n`nDOCUMENTATION:`nRefer to $docsPath for system capabilities and API references."
        $json | ConvertTo-Json -Depth 10 | Set-Content $agent.FullName
        Write-Host "Updated $($agent.Name)"
    } else {
        Write-Host "Skipping $($agent.Name) (already has docs)"
    }
}

$agents = Get-ChildItem .openclaw/agents/*.json
foreach ($agentFile in $agents) {
    $json = Get-Content $agentFile.FullName | ConvertFrom-Json
    $agentName = $json.id

    # Define new skill instructions based on role
    $skillInstruction = ""
    if ($agentName -eq "sentinel") {
        $skillInstruction = "`n`nNEW SKILLS (SACS-2026):`n- use `database` for deep JSON/log integrity checks.`n- use `file-organizer` for audit log management.`n- Read `skills/database/README.md` before first use."
    }
    elseif ($agentName -match "hype|dmarket|waxpeer|steam") {
        $skillInstruction = "`n`nNEW SKILLS (SACS-2026):`n- use `mcporter` for extended API connectivity and market analysis.`n- Read `skills/mcporter/README.md` before first use to understand API limits."
    }
    elseif ($agentName -match "ops|sec|engine") {
        $skillInstruction = "`n`nNEW SKILLS (SACS-2026):`n- use `agent-development` for automated code review and testing.`n- use `file-organizer` for workspace maintenance.`n- Read `skills/agent-development/README.md` before first use."
    }

    # Append if not already present
    if ($json.system -notmatch "SACS-2026") {
        $json.system += $skillInstruction
        $json | ConvertTo-Json -Depth 10 | Set-Content $agentFile.FullName
        Write-Host "Upgraded $($agentName) with SACS-2026 protocols."
    } else {
        Write-Host "$($agentName) already upgraded."
    }
}

