        $json.system = $system + $updateText
        $json | ConvertTo-Json -Depth 10 | Set-Content $agentFile.FullName
        Write-Host "Injected final skill docs into $($json.name)"
    } else {
        Write-Host "$($json.name) already has final docs."
    }
}

